DROP TABLE IF EXISTS `core_nguoidung`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `core_nguoidung` (
  `password` varchar(128) COLLATE utf8mb4_unicode_ci NOT NULL,
  `last_login` datetime(6) DEFAULT NULL,
  `is_superuser` tinyint(1) NOT NULL,
  `username` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `first_name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `last_name` varchar(150) COLLATE utf8mb4_unicode_ci NOT NULL,
  `email` varchar(254) COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_staff` tinyint(1) NOT NULL,
  `is_active` tinyint(1) NOT NULL,
  `date_joined` datetime(6) NOT NULL,
  `id_nguoi_dung` int NOT NULL AUTO_INCREMENT,
  `ho_va_ten` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `vai_tro` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `trang_thai` tinyint(1) NOT NULL,
  `id_to_chuc_id` int DEFAULT NULL,
  `bio` longtext COLLATE utf8mb4_unicode_ci,
  `ky_nang` longtext COLLATE utf8mb4_unicode_ci,
  `ready_to_work` tinyint(1) NOT NULL,
  `hinh_anh_logo` longtext COLLATE utf8mb4_unicode_ci,
  PRIMARY KEY (`id_nguoi_dung`),
  UNIQUE KEY `username` (`username`),
  KEY `core_nguoidung_id_to_chuc_id_8a9fd54c_fk_core_tochuc_id_to_chuc` (`id_to_chuc_id`),
  CONSTRAINT `core_nguoidung_id_to_chuc_id_8a9fd54c_fk_core_tochuc_id_to_chuc` FOREIGN KEY (`id_to_chuc_id`) REFERENCES `core_tochuc` (`id_to_chuc`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
