INSERT INTO `lms_cauhoi` VALUES (1,'Tên câu hỏi mới?',1,1,210),(2,'Tên câu hỏi mới?',1,1,211),(6,'Amazon ECR (Elastic Container Registry) đóng vai trò gì trong quá trình triển khai ứng dụng?',2,1,212),(7,'Trong Amazon ECS, thành phần nào dùng để khai báo Docker image cần sử dụng, cấu hình CPU, RAM và các biến môi trường (Environment Variables)?',2,2,212),(8,'Để đảm bảo ứng dụng web trên ECS có thể kết nối được với cơ sở dữ liệu RDS một cách an toàn, bước cấu hình mạng nào sau đây là chuẩn xác nhất?',2,3,212),(9,'Để duy trì ứng dụng web luôn có một số lượng container nhất định đang chạy và tự động thay thế nếu có container bị lỗi, bạn cần cấu hình tính năng nào trong ECS?',2,4,212),(10,'Khi kết nối ứng dụng web (ECS) với cơ sở dữ liệu (RDS), Endpoint (địa chỉ host), username và password thường được cung cấp cho container thông qua cơ chế nào để đảm bảo linh hoạt và bảo mật?',2,5,212),(46,'Tên câu hỏi mới?',1,1,214),(47,'Tên câu hỏi mới?',1,2,214),(48,'Tên câu hỏi mới?',1,3,214),(49,'Tên câu hỏi mới?',1,2,211);
