CREATE TABLE `lms_khoahoc` (
  `id_khoa_hoc` int NOT NULL AUTO_INCREMENT,
  `ten_khoa_hoc` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `mo_ta_chi_tiet` longtext COLLATE utf8mb4_unicode_ci,
  `gia_tien` double NOT NULL,
  `cong_khai` tinyint(1) NOT NULL,
  `ngay_tao` datetime(6) NOT NULL,
  `id_giang_vien_id` int NOT NULL,
  `danh_muc` varchar(100) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `gia_goc` double NOT NULL,
  `hinh_anh_thumbnail` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `mo_ta_ngan` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `ngay_cap_nhat` datetime(6) NOT NULL,
  `trinh_do` varchar(50) COLLATE utf8mb4_unicode_ci NOT NULL,
  `is_sequential` tinyint(1) NOT NULL,
  `so_nguoi_da_hoan_thanh` int unsigned NOT NULL,
  `so_nguoi_dang_hoc` int unsigned NOT NULL,
  `tong_so_danh_gia` int unsigned NOT NULL,
  `trung_binh_sao` decimal(3,2) NOT NULL,
  `tong_so_danh_gia_ntd` int unsigned NOT NULL,
  `trung_binh_sao_ntd` decimal(3,2) NOT NULL,
  `so_nguoi_co_viec_lam` int unsigned NOT NULL,
  `url_video_preview` varchar(500) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  PRIMARY KEY (`id_khoa_hoc`),
  KEY `lms_khoahoc_id_giang_vien_id_51214136_fk_core_nguo` (`id_giang_vien_id`),
  CONSTRAINT `lms_khoahoc_id_giang_vien_id_51214136_fk_core_nguo` FOREIGN KEY (`id_giang_vien_id`) REFERENCES `core_nguoidung` (`id_nguoi_dung`),
  CONSTRAINT `lms_khoahoc_chk_1` CHECK ((`so_nguoi_da_hoan_thanh` >= 0)),
  CONSTRAINT `lms_khoahoc_chk_2` CHECK ((`so_nguoi_dang_hoc` >= 0)),
  CONSTRAINT `lms_khoahoc_chk_3` CHECK ((`tong_so_danh_gia` >= 0)),
  CONSTRAINT `lms_khoahoc_chk_4` CHECK ((`tong_so_danh_gia_ntd` >= 0)),
  CONSTRAINT `lms_khoahoc_chk_5` CHECK ((`so_nguoi_co_viec_lam` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=27 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
