INSERT INTO `lms_khoahoc` VALUES (1,'Lập trình Python Cơ bản đến Nâng cao','Lộ trình Lập trình Python Cơ bản đến Nâng cao dành cho bạn. Khóa học được thiết kế cực kỳ đa dạng bài giảng từ lý thuyết video, tài liệu chuyên sâu cho tới bài kiểm tra năng lực.',1200000,1,'2026-04-02 02:42:17.073688',1,'Lập trình Backend',1800000,'https://img.youtube.com/vi/rfscVS0vtbw/maxresdefault.jpg','Thành thạo Lập trình Python Cơ bản đến Nâng cao chỉ sau thời gian ngắn học tập.','2026-05-05 07:52:11.593041','CoSo',0,1,5,1,4.00,2,4.50,1,''),(2,'Xây dựng Web với ReactJS Thực Chiến 2024','Lộ trình Xây dựng Web với ReactJS Thực Chiến 2024 dành cho bạn. Khóa học được thiết kế cực kỳ đa dạng bài giảng từ lý thuyết video, tài liệu chuyên sâu cho tới bài kiểm tra năng lực.',1500000,1,'2026-04-02 02:42:17.124419',2,'Lập trình Frontend',2250000,'https://img.youtube.com/vi/bMknfKXIFA8/maxresdefault.jpg','Thành thạo Xây dựng Web với ReactJS Thực Chiến 2024 chỉ sau thời gian ngắn học tập.','2026-04-03 06:51:54.105129','TrungCap',0,2,3,1,5.00,0,0.00,0,NULL),(3,'Backend Node.js/Express Căn bản','Lộ trình Backend Node.js/Express Căn bản dành cho bạn. Khóa học được thiết kế cực kỳ đa dạng bài giảng từ lý thuyết video, tài liệu chuyên sâu cho tới bài kiểm tra năng lực.',1300000,1,'2026-04-02 02:42:17.171043',3,'Lập trình Backend',1950000,'https://img.youtube.com/vi/Oe421EPjeBE/maxresdefault.jpg','Thành thạo Backend Node.js/Express Căn bản chỉ sau thời gian ngắn học tập.','2026-04-02 02:42:20.108081','CoSo',1,1,2,1,4.00,1,5.00,0,NULL),(4,'Khoá học JavaScript Toàn Tập','Lộ trình Khoá học JavaScript Toàn Tập dành cho bạn. Khóa học được thiết kế cực kỳ đa dạng bài giảng từ lý thuyết video, tài liệu chuyên sâu cho tới bài kiểm tra năng lực.',800000,1,'2026-04-02 02:42:17.268565',4,'Lập trình Web',1200000,'https://img.youtube.com/vi/W6NZfCO5SIk/maxresdefault.jpg','Thành thạo Khoá học JavaScript Toàn Tập chỉ sau thời gian ngắn học tập.','2026-04-03 02:27:07.107151','CoSo',0,1,2,0,0.00,3,5.00,0,NULL),(5,'Thực